import React from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import HomePage from './pages/homePage';

import QuiJeSuis from './pages/qui_je_suis';
import MesServices from './pages/services';
import MesCompetences from './pages/competences';
import MesProjets from './pages/projets';
import Contacts from './pages/contact';

const App = () => {
  return (
    <Router>
      <Header />
      <Switch>
        <Route exact path="/" component={HomePage} />

        <Route path="/qui_je_suis" component={QuiJeSuis} />
        <Route path="/services" component={MesServices} />
        <Route path="/competences" component={MesCompetences} />
        <Route path="/projets" component={MesProjets} />
        <Route path="/contacts" component={Contacts} />
      </Switch>
      <Footer />
    </Router>
  );
};

export default App;
